// Sadə namespace
namespace MyApp {
  export function greet(name: string): string {
    return `Hello, ${name}!`;
  }
}

console.log(MyApp.greet('Alice')); // Hello, Alice!

// İyerarxik namespace
namespace MyApp.Utilities {
  export function toUpperCase(str: string): string {
    return str.toUpperCase();
  }
}

console.log(MyApp.Utilities.toUpperCase('hello')); // HELLO

// Namespace-in çoxfayllı istifadəsi
// Fərz edək ki, bu kod utils.ts faylındadır
namespace MyApp {
  export function log(message: string): void {
    console.log(message);
  }
}

// Digər faylda (main.ts)
/// <reference path="utils.ts" />
MyApp.log('Test message'); // Test message

// Namespace nümunəsi
namespace MyApp {
  export function sayHello(): string {
    return 'Hello!';
  }
}

// Modul nümunəsi
// Fərz edək ki, bu kod module.ts faylındadır
export function sayHello(): string {
  return 'Hello!';
}

// main.ts faylında
// import { sayHello } from './module';
console.log(MyApp.sayHello()); // Hello!
// console.log(sayHello()); // Modul ilə

// Tip təhlükəsizliyi ilə namespace
namespace MyApp {
  export interface User {
    name: string;
    age: number;
  }

  export function printUser(user: User): void {
    console.log(`Name: ${user.name}, Age: ${user.age}`);
  }
}

const user: MyApp.User = { name: 'Alice', age: 25 };
MyApp.printUser(user); // Name: Alice, Age: 25
// MyApp.printUser({ name: 'Bob' }); // Xəta: age xüsusiyyəti yoxdur

// Səhvə yol açan namespace istifadəsi
namespace MyApp {
  export function calculate(value: number): number {
    return value * 2;
  }
}

// Yanlış istifadə
// console.log(MyApp.calculate('10')); // Xəta: string number tipinə uyğun deyil
console.log(MyApp.calculate(10)); // 20

// Real layihə ssenarisi
namespace MyApp.Data {
  export interface Product {
    id: number;
    name: string;
  }

  export function getProduct(id: number): Product {
    return { id, name: `Product ${id}` };
  }
}

const product = MyApp.Data.getProduct(1);
console.log(product.name); // Product 1

