// console.log(sayHello()); // With module

// Type safety with namespace
namespace MyApp {
  export interface User {
    name: string;
    age: number;
  }

  export function printUser(user: User): void {
    console.log(`Name: ${user.name}, Age: ${user.age}`);
  }
}

const user: MyApp.User = { name: 'Alice', age: 25 };
MyApp.printUser(user); // Name: Alice, Age: 25
// MyApp.printUser({ name: 'Bob' }); // Error: Property 'age' is missing

// Error-prone namespace usage
namespace MyApp {
  export function calculate(value: number): number {
    return value * 2;
  }
}

// Incorrect usage
// console.log(MyApp.calculate('10')); // Error: Argument of type 'string' is not assignable to 'number'
console.log(MyApp.calculate(10)); // 20

// Real-world scenario
namespace MyApp.Data {
  export interface Product {
    id: number;
    name: string;
  }

  export function getProduct(id: number): Product {
    return { id, name: `Product ${id}` };
  }
}

const product = MyApp.Data.getProduct(1);
console.log(product.name); // Product 1

